// Template for config.js. Copy this file to config.js and fill in your
// Supabase project URL and anon key for local development.
//
// IMPORTANT NOTE ABOUT SECURITY:
// The Supabase anon key is designed to be public. Anyone who visits the
// deployed site can read it from the browser. Real security comes from
// Row Level Security (RLS) policies on your tables — see the README /
// SQL block. Putting the key in a gitignored config.js just keeps it
// out of the repo history; it does not "hide" it from site visitors.
//
// In GitHub Pages production, this file is generated automatically by
// the deploy workflow (.github/workflows/deploy.yml) from the
// SUPABASE_URL and SUPABASE_ANON_KEY repository secrets.

window.SUPABASE_URL      = 'https://YOUR-PROJECT-REF.supabase.co';
window.SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5c... your anon key here ...';
